def canJump(nums: List[int]) -> bool:
    def canReach(index: int) -> bool:
        if index >= len(nums) - 1:
            return True
        if nums[index] == 0:
            return False

        for jump in range(1, nums[index] + 1):
            if canReach(index + jump):
                return True

        return False

    return canReach(0)

